import React, { useContext, useEffect, useState } from 'react';
import { mcqService, subjectService } from '../services/api';
import { toast } from 'react-toastify';
import styles from '../styles/inlineStyles';
import { AuthContext } from '../context/AuthContext';

const MCQ = () => {
  const { user } = useContext(AuthContext);

  const [subjects, setSubjects] = useState([]);
  const [topics, setTopics] = useState([]);
  const [selectedSubject, setSelectedSubject] = useState('');
  const [selectedTopic, setSelectedTopic] = useState('');
  const [mcqs, setMcqs] = useState([]);
  const [examQuestions, setExamQuestions] = useState([]);
  const [examAnswers, setExamAnswers] = useState({});
  const [examResult, setExamResult] = useState(null);
  const [attemptHistory, setAttemptHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [submittingExam, setSubmittingExam] = useState(false);
  const [userScore, setUserScore] = useState(null);
  const [editingMcqId, setEditingMcqId] = useState(null);
  const [formData, setFormData] = useState({
    question: '',
    difficulty: 'medium',
    explanation: '',
    options: ['', '', '', ''],
    correctOption: 0
  });

  const isTutor = user?.role === 'tutor' || user?.role === 'admin';
  const isStudent = user?.role === 'student';

  useEffect(() => {
    fetchSubjects();
  }, []);

  useEffect(() => {
    if (selectedSubject) {
      fetchTopics(selectedSubject);
    } else {
      setTopics([]);
      setSelectedTopic('');
    }
  }, [selectedSubject]);

  useEffect(() => {
    if (isTutor) {
      fetchMCQsForTutor();
    }
    if (isStudent) {
      fetchUserScore();
      fetchAttemptHistory();
    }
    setLoading(false);
  }, [isTutor, isStudent, selectedSubject, selectedTopic]);

  const fetchSubjects = async () => {
    try {
      const response = await subjectService.getAllSubjects();
      setSubjects(response.data || []);
    } catch (error) {
      toast.error('Failed to fetch subjects');
    }
  };

  const fetchTopics = async (subjectId) => {
    try {
      const response = await subjectService.getTopicsBySubject(subjectId);
      setTopics(response.data || []);
    } catch (error) {
      toast.error('Failed to fetch topics');
    }
  };

  const fetchMCQsForTutor = async () => {
    try {
      const response = await mcqService.getAllMCQs({
        subjectId: selectedSubject || undefined,
        topicId: selectedTopic || undefined,
        mine: true
      });
      setMcqs(response.data || []);
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to fetch MCQs');
    } finally {
      setLoading(false);
    }
  };

  const fetchUserScore = async () => {
    if (!isStudent) {
      return;
    }

    try {
      const response = await mcqService.getQuizScore({
        subjectId: selectedSubject || undefined,
        topicId: selectedTopic || undefined
      });
      setUserScore(response.data);
    } catch (error) {
      setUserScore(null);
    }
  };

  const fetchAttemptHistory = async () => {
    if (!isStudent) {
      return;
    }

    try {
      const response = await mcqService.getMyMockExamAttempts();
      setAttemptHistory(response.data || []);
    } catch (error) {
      setAttemptHistory([]);
    }
  };

  const resetForm = () => {
    setFormData({
      question: '',
      difficulty: 'medium',
      explanation: '',
      options: ['', '', '', ''],
      correctOption: 0
    });
    setEditingMcqId(null);
  };

  const handleOptionTextChange = (index, value) => {
    setFormData((prev) => {
      const nextOptions = [...prev.options];
      nextOptions[index] = value;
      return { ...prev, options: nextOptions };
    });
  };

  const handleCreateOrUpdateMCQ = async (e) => {
    e.preventDefault();

    if (!selectedSubject || !selectedTopic) {
      toast.error('Please select subject and topic first');
      return;
    }

    if (!formData.question.trim()) {
      toast.error('Question is required');
      return;
    }

    const hasEmptyOption = formData.options.some(option => !option.trim());
    if (hasEmptyOption) {
      toast.error('All options (A, B, C, D) are required');
      return;
    }

    const payload = {
      question: formData.question,
      subject: selectedSubject,
      topic: selectedTopic,
      difficulty: formData.difficulty,
      explanation: formData.explanation,
      options: formData.options.map((option, index) => ({
        text: option,
        isCorrect: index === Number(formData.correctOption)
      }))
    };

    try {
      if (editingMcqId) {
        await mcqService.updateMCQ(editingMcqId, payload);
        toast.success('MCQ updated successfully');
      } else {
        await mcqService.createMCQ(payload);
        toast.success('MCQ created successfully');
      }

      resetForm();
      fetchMCQsForTutor();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to save MCQ');
    }
  };

  const handleEditMCQ = (mcq) => {
    setEditingMcqId(mcq._id);
    setSelectedSubject(mcq.subject?._id || mcq.subject || '');
    setSelectedTopic(mcq.topic?._id || mcq.topic || '');
    setFormData({
      question: mcq.question,
      difficulty: mcq.difficulty || 'medium',
      explanation: mcq.explanation || '',
      options: (mcq.options || []).map(option => option.text).slice(0, 4),
      correctOption: Math.max(0, (mcq.options || []).findIndex(option => option.isCorrect))
    });
  };

  const handleDeleteMCQ = async (mcqId) => {
    if (!window.confirm('Delete this MCQ?')) {
      return;
    }

    try {
      await mcqService.deleteMCQ(mcqId);
      toast.success('MCQ deleted successfully');
      fetchMCQsForTutor();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to delete MCQ');
    }
  };

  const handleStartExam = async () => {
    if (!selectedSubject) {
      toast.error('Please select a subject to start the exam');
      return;
    }

    try {
      const response = await mcqService.startMockExam(selectedSubject, selectedTopic || undefined);
      setExamQuestions(response.data.questions || []);
      setExamAnswers({});
      setExamResult(null);
      toast.success(`Mock exam started with ${response.data.totalQuestions} questions`);
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to start mock exam');
    }
  };

  const handleSelectExamAnswer = (mcqId, optionIndex) => {
    setExamAnswers(prev => ({ ...prev, [mcqId]: optionIndex }));
  };

  const handleSubmitExam = async () => {
    if (examQuestions.length === 0) {
      return;
    }

    setSubmittingExam(true);

    const payload = {
      subjectId: selectedSubject,
      topicId: selectedTopic || undefined,
      answers: examQuestions.map(question => ({
        mcqId: question._id,
        selectedOption: Number.isInteger(examAnswers[question._id]) ? examAnswers[question._id] : -1
      }))
    };

    try {
      const response = await mcqService.submitMockExam(payload);
      setExamResult(response.data.result);
      setExamQuestions([]);
      setExamAnswers({});
      fetchUserScore();
      fetchAttemptHistory();
      toast.success('Exam submitted and auto-marked successfully');
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to submit exam');
    } finally {
      setSubmittingExam(false);
    }
  };

  if (loading) {
    return (
      <div style={styles.loading}>
        <svg style={styles.spinnerSvg} viewBox="0 0 50 50">
          <circle cx="25" cy="25" r="20" fill="none" stroke="#e6e6e6" strokeWidth="5"></circle>
          <path d="M45 25a20 20 0 0 1-20 20" stroke="#667eea" strokeWidth="5" strokeLinecap="round" fill="none">
            <animateTransform attributeName="transform" type="rotate" from="0 25 25" to="360 25 25" dur="1s" repeatCount="indefinite" />
          </path>
        </svg>
      </div>
    );
  }

  return (
    <div style={{ ...styles.container, marginTop: '30px' }}>
      <h1 style={{ marginBottom: '30px' }}>MCQ Mock Exams</h1>

      <div style={{ ...styles.card, marginBottom: '30px' }}>
        <label style={styles.label}>Subject</label>
        <select value={selectedSubject} onChange={(e) => setSelectedSubject(e.target.value)} style={styles.input}>
          <option value="">Select Subject</option>
          {subjects.map(subject => (
            <option key={subject._id} value={subject._id}>{subject.name}</option>
          ))}
        </select>

        <label style={styles.label}>Topic (Optional for Student Exam)</label>
        <select value={selectedTopic} onChange={(e) => setSelectedTopic(e.target.value)} style={styles.input}>
          <option value="">All Topics</option>
          {topics.map(topic => (
            <option key={topic._id} value={topic._id}>{topic.name}</option>
          ))}
        </select>
      </div>

      {isTutor && (
        <div style={styles.card}>
          <h2>{editingMcqId ? 'Edit MCQ Question' : 'Create MCQ Question'}</h2>
          <form onSubmit={handleCreateOrUpdateMCQ}>
            <label style={styles.label}>Question</label>
            <textarea
              style={{ ...styles.input, minHeight: '80px' }}
              value={formData.question}
              onChange={(e) => setFormData(prev => ({ ...prev, question: e.target.value }))}
              placeholder="Enter question text"
            />

            {['A', 'B', 'C', 'D'].map((label, index) => (
              <div key={label}>
                <label style={styles.label}>Option {label}</label>
                <input
                  type="text"
                  style={styles.input}
                  value={formData.options[index] || ''}
                  onChange={(e) => handleOptionTextChange(index, e.target.value)}
                />
              </div>
            ))}

            <label style={styles.label}>Correct Answer</label>
            <select
              style={styles.input}
              value={formData.correctOption}
              onChange={(e) => setFormData(prev => ({ ...prev, correctOption: Number(e.target.value) }))}
            >
              <option value={0}>A</option>
              <option value={1}>B</option>
              <option value={2}>C</option>
              <option value={3}>D</option>
            </select>

            <label style={styles.label}>Difficulty</label>
            <select
              style={styles.input}
              value={formData.difficulty}
              onChange={(e) => setFormData(prev => ({ ...prev, difficulty: e.target.value }))}
            >
              <option value="easy">Easy</option>
              <option value="medium">Medium</option>
              <option value="hard">Hard</option>
            </select>

            <label style={styles.label}>Explanation (Feedback)</label>
            <textarea
              style={{ ...styles.input, minHeight: '70px' }}
              value={formData.explanation}
              onChange={(e) => setFormData(prev => ({ ...prev, explanation: e.target.value }))}
              placeholder="Explain why the correct answer is correct"
            />

            <div style={{ display: 'flex', gap: '10px' }}>
              <button type="submit" style={styles.button}>
                {editingMcqId ? 'Update Question' : 'Create Question'}
              </button>
              {editingMcqId && (
                <button type="button" style={styles.buttonDanger} onClick={resetForm}>
                  Cancel Edit
                </button>
              )}
            </div>
          </form>
        </div>
      )}

      {isTutor && (
        <div style={{ marginTop: '20px' }}>
          <h2>Manage MCQ Questions</h2>
          <div style={{ display: 'grid', gap: '15px' }}>
            {mcqs.map(mcq => (
              <div key={mcq._id} style={styles.card}>
                <h3>{mcq.question}</h3>
                <div style={{ margin: '10px 0' }}>
                  {(mcq.options || []).map((option, idx) => (
                    <div key={`${mcq._id}-${idx}`} style={{ marginBottom: '6px' }}>
                      {String.fromCharCode(65 + idx)}. {option.text} {option.isCorrect ? '(Correct)' : ''}
                    </div>
                  ))}
                </div>
                <div style={{ display: 'flex', gap: '10px' }}>
                  <button style={styles.button} onClick={() => handleEditMCQ(mcq)}>Edit</button>
                  <button style={styles.buttonDanger} onClick={() => handleDeleteMCQ(mcq._id)}>Delete</button>
                </div>
              </div>
            ))}
          </div>
          {mcqs.length === 0 && <div style={styles.alertInfo}>No MCQ questions found for selected filters.</div>}
        </div>
      )}

      {isStudent && userScore && (
        <div style={{ ...styles.card, marginBottom: '30px', background: '#e8f5e9' }}>
          <h2>Your Score</h2>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(150px, 1fr))', gap: '20px', marginTop: '20px' }}>
            <div>
              <p style={{ fontSize: '24px', fontWeight: 'bold', color: '#388e3c' }}>
                {userScore.correctAttempts} / {userScore.totalAttempts}
              </p>
              <p>Correct Answers</p>
            </div>
            <div>
              <p style={{ fontSize: '24px', fontWeight: 'bold', color: '#1976d2' }}>
                {userScore.scorePercentage}%
              </p>
              <p>Percentage</p>
            </div>
          </div>
        </div>
      )}

      {isStudent && (
        <div style={styles.card}>
          <h2>Attempt Mock Exam (Up to 10 MCQs)</h2>
          <button style={styles.button} onClick={handleStartExam}>Start Mock Exam</button>
        </div>
      )}

      {isStudent && examQuestions.length > 0 && (
        <div style={{ marginTop: '20px' }}>
          <h2>Exam Questions</h2>
          {examQuestions.map((question, qIdx) => (
            <div key={question._id} style={styles.card}>
              <h3>{qIdx + 1}. {question.question}</h3>
              <div style={{ marginTop: '10px' }}>
                {(question.options || []).map((option, optIdx) => (
                  <label key={`${question._id}-${optIdx}`} style={{ display: 'block', marginBottom: '10px' }}>
                    <input
                      type="radio"
                      name={`answer-${question._id}`}
                      checked={examAnswers[question._id] === optIdx}
                      onChange={() => handleSelectExamAnswer(question._id, optIdx)}
                      style={{ marginRight: '8px' }}
                    />
                    {String.fromCharCode(65 + optIdx)}. {option.text}
                  </label>
                ))}
              </div>
            </div>
          ))}
          <button style={styles.button} onClick={handleSubmitExam} disabled={submittingExam}>
            {submittingExam ? 'Submitting...' : 'Submit Exam'}
          </button>
        </div>
      )}

      {isStudent && examResult && (
        <div style={{ ...styles.card, marginTop: '20px' }}>
          <h2>Exam Result</h2>
          <p><strong>Score:</strong> {examResult.correctAnswers}/{examResult.totalQuestions} ({examResult.scorePercentage}%)</p>
          <p><strong>Correct:</strong> {examResult.correctAnswers} | <strong>Wrong:</strong> {examResult.wrongAnswers}</p>
          <p><strong>Feedback:</strong> {examResult.feedback}</p>
          <h3 style={{ marginTop: '20px' }}>Correct vs Wrong Answers</h3>
          {(examResult.answers || []).map((answer, idx) => (
            <div
              key={`${answer.mcq}-${idx}`}
              style={{
                border: `1px solid ${answer.isCorrect ? '#c8e6c9' : '#ffcdd2'}`,
                padding: '12px',
                borderRadius: '6px',
                marginBottom: '10px',
                background: answer.isCorrect ? '#f1f8e9' : '#ffebee'
              }}
            >
              <p><strong>Q:</strong> {answer.question}</p>
              <p>
                <strong>Your answer:</strong> {answer.selectedOption >= 0 ? String.fromCharCode(65 + answer.selectedOption) : 'Not Answered'} | 
                <strong> Correct:</strong> {String.fromCharCode(65 + answer.correctOption)}
              </p>
              <p><strong>Status:</strong> {answer.isCorrect ? 'Correct' : 'Wrong'}</p>
              {!!answer.explanation && <p><strong>Explanation:</strong> {answer.explanation}</p>}
            </div>
          ))}
        </div>
      )}

      {isStudent && (
        <div style={{ ...styles.card, marginTop: '20px' }}>
          <h2>Previous Mock Exam Attempts</h2>
          {(attemptHistory || []).slice(0, 10).map((attempt) => (
            <div key={attempt._id} style={{ ...styles.listItem, display: 'block' }}>
              <p><strong>Date:</strong> {new Date(attempt.attemptedAt).toLocaleString()}</p>
              <p><strong>Subject:</strong> {attempt.subject?.name || 'N/A'}</p>
              <p><strong>Topic:</strong> {attempt.topic?.name || 'All Topics'}</p>
              <p><strong>Score:</strong> {attempt.correctAnswers}/{attempt.totalQuestions} ({attempt.scorePercentage}%)</p>
              <p><strong>Feedback:</strong> {attempt.feedback}</p>
            </div>
          ))}
          {attemptHistory.length === 0 && (
            <div style={styles.alertInfo}>No previous attempts found.</div>
          )}
        </div>
      )}

      {!isStudent && !isTutor && (
        <div style={styles.alertWarning}>
          Your role does not have MCQ exam access.
        </div>
      )}

      {isStudent && attemptHistory.length === 0 && !examResult && (
        <div style={styles.alertInfo}>
          No mock exam attempts yet. Select a subject and start your first exam.
        </div>
      )}
    </div>
  );
};

export default MCQ;
